override suspend fun test(apiKey: String?): TestResult = withContext(Dispatchers.IO) {
    try {
        val testKey = apiKey?.trim() ?: preferenceManager.getGroqApiKey()
            ?: return@withContext TestResult(false, "API Key not configured")

        // 验证 API Key 格式
        if (testKey.isBlank()) {
            return@withContext TestResult(false, "API Key 不能为空")
        }

        if (!testKey.startsWith("gsk_")) {
            return@withContext TestResult(false, "API Key 格式错误（应以 gsk_ 开头）")
        }

        // 发送测试请求（获取模型列表）
        val request = Request.Builder()
            .url("https://api.groq.com/openai/v1/models")
            .addHeader("Authorization", "Bearer $testKey")
            .addHeader("User-Agent", "VideoDownloadApp/1.0")
            .addHeader("Accept", "application/json")
            .get()
            .build()

        val response = client.newCall(request).execute()

        if (response.isSuccessful) {
            // 保存 API Key
            if (apiKey != null) {
                preferenceManager.setGroqApiKey(apiKey)
            }
            TestResult(true, "连接成功")
        } else {
            val errorBody = response.body?.string() ?: "Unknown error"
            TestResult(false, "连接失败 (${response.code}): $errorBody")
        }
    } catch (e: Exception) {
        TestResult(false, "连接失败: ${e.message}")
    }
}
